\n-- =====================================================================\n-- Novos Produtos Incharge (Adicionados Manualmente)\n-- =====================================================================\n\n-- 1. Inserção de Produtos\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (28, 'incharge-home-5', 'INCHARGE HOME 5', 'incharge', 'estacoes', '7,4 kW', '210~240V AC Monofásico', 'Residencial', 'Cabo fixo Tipo 2 (5m)', 'Estação de carregamento residencial compacta com cabo de 5 metros e conector Tipo 2.', 'O INCHARGE HOME 5 é uma estação de carregamento AC para uso residencial, projetada para carregar veículos elétricos e híbridos Plug-in. Com indicação de status por LEDs, montagem em parede ou totem e cabo de 5 metros com conector Tipo 2, oferece praticidade e segurança para o carregamento doméstico. Sem controle de carga ou comunicação remota, ideal para uso simples e direto.', 'static/produtos/incharge-home-5.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (29, 'incharge-home-7', 'INCHARGE HOME 7', 'incharge', 'estacoes', '7,4 kW', '210~240V AC Monofásico', 'Residencial', 'Cabo fixo Tipo 2 (7m)', 'Estação de carregamento residencial com cabo longo de 7 metros e conector Tipo 2.', 'O INCHARGE HOME 7 é idêntico ao HOME 5 em especificações elétricas, mas oferece um cabo de 7 metros para maior flexibilidade no posicionamento do veículo. Ideal para garagens onde a tomada de recarga do carro fica mais distante da parede. Indicação de status por LEDs, montagem em parede ou totem e proteção IP54.', 'static/produtos/incharge-home-7.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (30, 'incharge-home-trifasico-5', 'INCHARGE HOME Trifásico 5', 'incharge', 'estacoes', '22 kW', '365~415V AC Trifásico', 'Residencial, Corporativo', 'Cabo fixo Tipo 2 (5m)', 'Estação de carregamento residencial trifásica de 22kW com cabo de 5 metros.', 'O INCHARGE HOME Trifásico 5 (INC3X32H5) oferece carregamento AC trifásico de 22kW para veículos que suportam esse modo de recarga. Com cabo de 5 metros e conector Tipo 2, é indicado para residências e condomínios com rede trifásica 380V disponível. Indica o status por LEDs e pode ser montado em parede ou totem.', 'static/produtos/incharge-home-trifasico-5.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (31, 'incharge-home-trifasico-7', 'INCHARGE HOME Trifásico 7', 'incharge', 'estacoes', '22 kW', '365~415V AC Trifásico', 'Residencial, Corporativo', 'Cabo fixo Tipo 2 (7m)', 'Estação de carregamento residencial trifásica de 22kW com cabo longo de 7 metros.', 'O INCHARGE HOME Trifásico 7 (INC3X32H7) combina a potência de 22kW trifásico com um cabo de 7 metros para maior flexibilidade de posicionamento. Ideal para garagens amplas ou condomínios com rede 380V. Indicação por LEDs e montagem em parede ou totem.', 'static/produtos/incharge-home-trifasico-7.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (32, 'incharge-plus-74kw', 'INCHARGE 7,4kW PLUS', 'incharge', 'estacoes', '7,4 kW', '210~240V AC Monofásico/Bifásico', 'Residencial, Corporativo, Condomínios', 'Cabo fixo Tipo 2 (5m)', 'Carregador AC compacto com design premiado internacionalmente, para uso em parede ou totem.', 'O INCHARGE 7,4kW PLUS é um carregador veicular AC com design premiado (iF Design Award 2021 e A'' Design Award Bronze 2020). Com display cromático indicativo, cabo de 5 metros e conector Tipo 2, é indicado para uso em residências, condomínios e pontos comerciais. Não possui comunicação remota ou controle de carga — ideal para instalações simples e diretas.', 'static/produtos/incharge-plus-74kw.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (33, 'incharge-smart-74kw', 'INCHARGE 7,4kW SMART', 'incharge', 'estacoes', '7,4 kW', '210~240V AC Monofásico/Bifásico', 'Corporativo, Condomínios, Pontos Comerciais', 'Cabo fixo Tipo 2 (5m)', 'Carregador AC inteligente com controle de acesso via NFC/App e comunicação OCPP 1.6J.', 'O INCHARGE 7,4kW SMART é a versão conectada da linha PLUS. Além do design premiado e proteção IP54, conta com medidor de energia integrado, controle de acesso por cartão NFC ou App, comunicação OCPP 1.6J e controle de carga remoto. Inclui Gateway de conexão para integração com o servidor INCHARGE. Indicado para condomínios, estacionamentos e pontos comerciais que precisam de gestão de recargas.', 'static/produtos/incharge-smart-74kw.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (34, 'incharge-plus-22kw', 'INCHARGE 22kW PLUS', 'incharge', 'estacoes', '22 kW', '365~415V AC Trifásico', 'Corporativo, Condomínios, Frotas', 'Cabo fixo Tipo 2 (5m)', 'Carregador AC trifásico de 22kW com design premiado, para uso em parede ou totem.', 'O INCHARGE 22kW PLUS é a versão trifásica de alta potência da linha PLUS. Com 22kW de potência AC, carrega veículos compatíveis de forma significativamente mais rápida que carregadores monofásicos. Design premiado internacionalmente, proteção IP54 para uso interno e externo, cabo de 5 metros com conector Tipo 2. Sem comunicação remota — ideal para instalações corporativas simples.', 'static/produtos/incharge-plus-22kw.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (35, 'incharge-smart-22kw', 'INCHARGE 22kW SMART', 'incharge', 'estacoes', '22 kW', '365~415V AC Trifásico', 'Corporativo, Condomínios, Frotas, Pontos Comerciais', 'Cabo fixo Tipo 2 (5m)', 'Carregador AC trifásico de 22kW com controle de acesso NFC/App e OCPP 1.6J.', 'O INCHARGE 22kW SMART combina a alta potência de 22kW trifásico com recursos de conectividade completos: controle de acesso por cartão NFC ou App, comunicação OCPP 1.6J, medidor de energia integrado e controle de carga remoto. Inclui Gateway de conexão. Indicado para estacionamentos comerciais, frotas corporativas e condomínios que precisam de gestão centralizada de recargas.', 'static/produtos/incharge-smart-22kw.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (36, 'incharge-emvs-30kw', 'INCHARGE EMVS 30kW', 'incharge', 'estacoes', '30 kW', '400 Vca, 3P+N+PE (304~456 Vca)', 'Corporativo, Estacionamentos, Frotas, Pontos Comerciais', 'Cabo fixo CCS2 (3m)', 'Wallbox DC de 30kW com display touchscreen de 10,4", OCPP 1.6J e até 96,5% de eficiência.', 'O INCHARGE EMVS 30kW é uma estação de carregamento rápido DC em formato wallbox, para montagem em parede ou totem. Com 30kW de potência DC, display touchscreen TFT de 10,4", conector CCS2, comunicação via LAN e protocolo OCPP 1.6J, atende estacionamentos, frotas e pontos comerciais que precisam de carregamento rápido em espaço reduzido. Eficiência geral de até 96,5% e operação de -35°C a 60°C.', 'static/produtos/incharge-emvs-30kw.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (37, 'incharge-fast-charge-60kw', 'INCHARGE Fast Charge 60kW', 'incharge', 'estacoes', '60 kW', '304~456V AC 3P+N+T (50/60 Hz)', 'Corporativo, Estacionamentos, Postos, Frotas, Uso Público', '2× CCS2 (auto portante)', 'Carregador DC rápido autosuportado de 60kW com 2 saídas CCS2, display touch 10,4" e OCPP 1.6J.', 'O INCHARGE Fast Charge 60kW (INC60kW-DC) é um carregador DC rápido em formato totem autosuportado, com dois conectores CCS2. Estratégia de carregamento flexível: 60+0, 0+60 ou 30+30 kW por conector. Display touchscreen de 10,4", controle de acesso local/cartão/app, comunicação OCPP 1.6J e controle de carga. Tensão de saída de 150 a 1000 VDC com corrente máxima de 200A. Robusto, com proteção IP54, IK10 e operação de -20°C a 60°C.', 'static/produtos/incharge-fast-charge-60kw.webp');\nINSERT INTO `produtos` (`id`, `slug`, `nome`, `marca_id`, `categoria_id`, `potencia`, `tensao`, `aplicacao`, `tipo`, `resumo`, `descricao`, `imagem`) VALUES (38, 'incharge-fast-charge-150kw', 'INCHARGE Fast Charge 150kW', 'incharge', 'estacoes', '150 kW', '304~456V AC 3P+N+T (50/60 Hz)', 'Postos de Recarga, Uso Público, Frotas de Alta Demanda', '2× CCS2 (auto portante)', 'Carregador DC ultrarrápido autosuportado de 150kW com 2 saídas CCS2, display touch 10,4" e OCPP 1.6J.', 'O INCHARGE Fast Charge 150kW (INC150kW-DC) é o carregador DC de maior potência da linha INCHARGE. Em formato totem autosuportado com dois conectores CCS2, entrega até 150kW com estratégias de divisão de carga flexíveis: 150+0, 0+150 ou 90+60 kW. Display touchscreen de 10,4", controle de acesso multicanal, OCPP 1.6J e tensão de saída de 150 a 1000 VDC com 200A máximos. Ideal para postos de recarga de alta demanda e frotas comerciais.', 'static/produtos/incharge-fast-charge-150kw.webp');\n\n-- 2. Inserção de Diferenciais\nINSERT INTO `produto_diferenciais` (`produto_id`, `diferencial`, `ordem`) VALUES (28, 'Indicação de status por LEDs (Carregando, Conectado, Erro)', 0);\nINSERT INTO `produto_diferenciais` (`produto_id`, `diferencial`, `ordem`) VALUES (28, 'Montagem em parede ou totem', 1);\nINSERT INTO `produto_diferenciais` (`produto_id`, `diferencial`, `ordem`) VALUES (28, 'Proteção IP54 e IK10', 2);\nINSERT INTO `produto_diferenciais` 